import re
from pathlib import Path

import pytest

AC_UID = "546c22e4fddfaf20"
AC_TYPE = "data"

REPO_ROOT = Path(__file__).resolve().parents[3]
STYLE_INSPECTOR = REPO_ROOT / "agents" / "style-inspector.md"


def test_AC_13():
    """
    GIVEN: agents/style-inspector.md is read as text; the Standard 6 section is sliced; within that section the NEW exemption paragraph (anchored by '**Exemption (Cycle-2 user-facing...)**') is further sliced as a paragraph (from the anchor to the next blank line OR the next bold-heading-start OR the section end)
    WHEN:  the NEW-exemption-paragraph slice is inspected (paragraph-level scope, NOT section-level)
    THEN:  the NEW exemption paragraph contains ALL of: (a) literal 'spec-20260518-225715 §5.1' attribution, (b) at least one of the five spec §5.1 rank-label samples, (c) literal 'AskUserQuestion', (d) re-affirmation that BOTH code comments AND stderr/diagnostic strings remain English-only — all four MUST be inside this paragraph, NOT satisfiable by the existing line 320 paragraph (which is a separate exemption)
    """
    assert STYLE_INSPECTOR.is_file(), f"missing: {STYLE_INSPECTOR}"
    text = STYLE_INSPECTOR.read_text(encoding="utf-8")
    lines = text.splitlines()

    # Slice Standard 6 section
    sec_start = None
    sec_end = len(lines)
    for i, ln in enumerate(lines):
        if re.match(r"^### Standard 6: English Only", ln):
            sec_start = i
            break
    assert sec_start is not None, "Standard 6 section not found"
    for j in range(sec_start + 1, len(lines)):
        if re.match(r"^### Standard 7:", lines[j]):
            sec_end = j
            break
    section_lines = lines[sec_start:sec_end]

    # Slice NEW-exemption paragraph: anchor → next blank | next bold heading start | section end
    para_start = None
    anchor_re = re.compile(r"\*\*Exemption \(Cycle-2 user-facing[^)]*\)\*\*")
    for k, ln in enumerate(section_lines):
        if anchor_re.search(ln):
            para_start = k
            break
    assert para_start is not None, (
        "NEW '**Exemption (Cycle-2 user-facing...)**' paragraph anchor not found in Standard 6"
    )
    end_re = re.compile(r"^\s*$|^\*\*[^*]+\*\*:|^### Standard 7:")
    para_end = len(section_lines)
    for m in range(para_start + 1, len(section_lines)):
        if end_re.search(section_lines[m]):
            para_end = m
            break
    paragraph = "\n".join(section_lines[para_start:para_end])

    # (a) spec §5.1 attribution
    assert re.search(r"spec-20260518-225715\s+§5\.1", paragraph), (
        f"(a) missing literal 'spec-20260518-225715 §5.1' attribution in paragraph: {paragraph!r}"
    )

    # (b) at least one of the five rank-label samples; rank labels constructed
    # via \N{...} unicode escapes so this file contains zero raw CJK literals
    # (constraint: no CJK in committed code outside AC-02's detection regex).
    # Rank labels per spec section 5.1 (see docs/dev/specs/spec-20260518-225715.md):
    #   apprentice / junior / skilled / senior / master.
    APPRENTICE = (
        "\N{CJK UNIFIED IDEOGRAPH-89C1}"
        "\N{CJK UNIFIED IDEOGRAPH-4E60}"
        "\N{CJK UNIFIED IDEOGRAPH-5B66}"
        "\N{CJK UNIFIED IDEOGRAPH-5F92}"
    )
    JUNIOR = (
        "\N{CJK UNIFIED IDEOGRAPH-521D}"
        "\N{CJK UNIFIED IDEOGRAPH-7EA7}"
        "\N{CJK UNIFIED IDEOGRAPH-5DE5}"
        "\N{CJK UNIFIED IDEOGRAPH-5320}"
    )
    SKILLED = (
        "\N{CJK UNIFIED IDEOGRAPH-719F}"
        "\N{CJK UNIFIED IDEOGRAPH-7EC3}"
        "\N{CJK UNIFIED IDEOGRAPH-5DE5}"
        "\N{CJK UNIFIED IDEOGRAPH-5320}"
    )
    SENIOR = (
        "\N{CJK UNIFIED IDEOGRAPH-8D44}"
        "\N{CJK UNIFIED IDEOGRAPH-6DF1}"
        "\N{CJK UNIFIED IDEOGRAPH-5DE5}"
        "\N{CJK UNIFIED IDEOGRAPH-5320}"
    )
    MASTER = (
        "\N{CJK UNIFIED IDEOGRAPH-5B97}"
        "\N{CJK UNIFIED IDEOGRAPH-5E08}"
        "\N{CJK UNIFIED IDEOGRAPH-7EA7}"
    )
    rank_pattern = "|".join([APPRENTICE, JUNIOR, SKILLED, SENIOR, MASTER])
    rank_re = re.compile(rank_pattern)
    assert rank_re.search(paragraph), (
        f"(b) missing at least one of the five spec §5.1 rank-label samples in paragraph: {paragraph!r}"
    )

    # (c) AskUserQuestion citation
    assert "AskUserQuestion" in paragraph, (
        f"(c) missing 'AskUserQuestion' citation in paragraph: {paragraph!r}"
    )

    # (d) BOTH-sides re-affirmation (comments AND stderr/diagnostic)
    both_re = re.compile(
        r"(comments?\s+AND\s+(stderr|diagnostic)|(stderr|diagnostic)[^.]*(comments?|comment))(?![^.]*are\s+allowed)"
    )
    assert both_re.search(paragraph), (
        f"(d) missing BOTH-sides re-affirmation (comments AND stderr/diagnostic English-only) in paragraph: {paragraph!r}"
    )
